package main

import (
	"bytes"
	"encoding/json"
	"errors"
	"os"
	"reflect"
	"sort"
	"strings"
)

type entry struct {
	Case      string `json:"case"`
	Produced  []int  `json:"produced"`
	Trace     []int  `json:"slot_trace"`
	OrderUsed []int  `json:"order_used"`
	Packed    bool   `json:"packed"`
	Grouped   bool   `json:"grouped"`
	Reuse     bool   `json:"reuse"`
}

type rawDoc struct {
	Raw []entry `json:"raw"`
}

type finalDoc struct {
	Rows    []entry        `json:"rows"`
	Summary map[string]any `json:"summary"`
}

func readBuiltins(path string) ([]string, error) {
	b, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}
	lines := strings.Split(string(b), "\n")
	out := make([]string, 0, len(lines))
	for _, ln := range lines {
		ln = strings.TrimSpace(ln)
		if ln == "" {
			continue
		}
		out = append(out, ln)
	}
	return out, nil
}

func norm(e entry) entry {
	// normalize nil vs empty slices for stable comparisons
	if e.Produced == nil {
		e.Produced = []int{}
	}
	if e.Trace == nil {
		e.Trace = []int{}
	}
	if e.OrderUsed == nil {
		e.OrderUsed = []int{}
	}
	return e
}

func sameSix(a, b entry) bool {
	a = norm(a)
	b = norm(b)
	return reflect.DeepEqual(a.Produced, b.Produced) &&
		reflect.DeepEqual(a.Trace, b.Trace) &&
		reflect.DeepEqual(a.OrderUsed, b.OrderUsed) &&
		a.Packed == b.Packed &&
		a.Grouped == b.Grouped &&
		a.Reuse == b.Reuse
}

func mapByCase(rows []entry) (map[string]entry, map[string]int) {
	m := map[string]entry{}
	cnt := map[string]int{}
	for _, r := range rows {
		cnt[r.Case]++
		m[r.Case] = r // last wins for determinism
	}
	return m, cnt
}

func loadReport(path string) (*finalDoc, error) {
	b, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}
	var d finalDoc
	dec := json.NewDecoder(bytes.NewReader(b))
	dec.DisallowUnknownFields()
	if err := dec.Decode(&d); err != nil {
		return nil, err
	}
	return &d, nil
}

func main() {
	if len(os.Args) != 3 {
		panic("usage: align raw final")
	}
	rawPath := os.Args[1]
	finalPath := os.Args[2]

	builtins, err := readBuiltins("/app/config/sets.txt")
	if err != nil {
		panic(err)
	}

	buf, err := os.ReadFile(rawPath)
	if err != nil {
		panic(err)
	}
	var raw rawDoc
	if err := json.Unmarshal(buf, &raw); err != nil {
		panic(err)
	}

	rawBy, rawCnt := mapByCase(raw.Raw)

	agree := true

	// Duplicates in raw imply multiple requests collapsed; we still emit one row per case
	// (the last one deterministically) but cannot claim agreement.
	for _, c := range builtins {
		if rawCnt[c] != 1 {
			agree = false
		}
	}
	for c, n := range rawCnt {
		if n != 1 {
			agree = false
		}
		_ = c
	}

	// Ensure all built-in cases are present.
	for _, c := range builtins {
		if _, ok := rawBy[c]; !ok {
			agree = false
		}
	}

	// Build rows in deterministic order: builtins order (then any extras sorted).
	rows := make([]entry, 0, len(rawBy))
	seen := map[string]bool{}
	for _, c := range builtins {
		if r, ok := rawBy[c]; ok {
			rows = append(rows, r)
			seen[c] = true
		}
	}
	extra := make([]string, 0)
	for c := range rawBy {
		if !seen[c] {
			extra = append(extra, c)
		}
	}
	sort.Strings(extra)
	for _, c := range extra {
		agree = false // extras not in built-in list
		rows = append(rows, rawBy[c])
	}

	// Verify new rows match raw on the six required fields by case.
	for _, r := range rows {
		if rr, ok := rawBy[r.Case]; !ok || !sameSix(r, rr) {
			agree = false
		}
	}

	// Compare against prior report.json if it exists.
	if prior, err := loadReport(finalPath); err == nil {
		priorBy, priorCnt := mapByCase(prior.Rows)
		// Missing/extra/duplicate rows in prior means disagreement.
		for _, c := range builtins {
			if priorCnt[c] != 1 {
				agree = false
			}
			pr, okP := priorBy[c]
			rr, okR := rawBy[c]
			if !okP || !okR || !sameSix(pr, rr) {
				agree = false
			}
		}
		for c, n := range priorCnt {
			if n != 1 {
				agree = false
			}
			if !contains(builtins, c) {
				agree = false
			}
		}
	} else if !errors.Is(err, os.ErrNotExist) {
		// unreadable prior report: cannot claim agreement
		agree = false
	}

	doc := finalDoc{
		Rows: rows,
		Summary: map[string]any{
			"total": len(builtins),
			"agree": agree,
		},
	}
	out, err := json.MarshalIndent(doc, "", "  ")
	if err != nil {
		panic(err)
	}
	if err := os.WriteFile(finalPath, append(out, '\n'), 0o644); err != nil {
		panic(err)
	}
}

func contains(a []string, s string) bool {
	for _, x := range a {
		if x == s {
			return true
		}
	}
	return false
}
